8199	\begin{lemma}[The category of schemes is finitary extensive]
8200	  \label{lem:finitaryExtensive_scheme_mathlib}
8201	  \lean{AlgebraicGeometry.instFinitaryExtensiveScheme}
8202	  \mathlibok
8203	  \textit{Provided by Mathlib.}
8204	  The category \(\operatorname{Scheme}\) is finitary extensive: finite coproducts are disjoint
8205	  and universal (stable under pullback). In particular it is finitary pre-extensive and has
8206	  finite coproducts and pullbacks, so the abstract distributivity of
8207	  Lemma~\ref{lem:isIso_sigmaDesc_map_mathlib} applies at \(\mathcal{C} = \operatorname{Scheme}\).
8208	\end{lemma}
8209	
8210	\begin{lemma}[Coproducts distribute over the binary fibre product]
8211	  \label{lem:isIso_sigmaDesc_map_mathlib}
8212	  \lean{CategoryTheory.FinitaryPreExtensive.isIso_sigmaDesc_map}
8213	  \mathlibok
8214	  \textit{Provided by Mathlib.}
8215	  In a finitary pre-extensive category with pullbacks, for finite index types \(\iota, \iota'\),
8216	  a base \(S\), and families \((X_i \to S)_i\), \((Y_j \to S)_j\), the canonical map
8217	  \(\coprod_{(i,j)} (X_i \times_S Y_j) \to (\coprod_i X_i) \times_S (\coprod_j Y_j)\),
8218	  \(\operatorname{Sigma.desc}\) of the pullback maps, is an isomorphism. Taking one family to be a
8219	  singleton gives the one-sided distributivity
8220	  \((\coprod_i X_i) \times_S Y \cong \coprod_i (X_i \times_S Y)\) used in the induction of
8221	  Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8222	\end{lemma}
8223	
8224	\begin{lemma}[Pullback of two open immersions is the intersection open]
8225	  \label{lem:isPullback_opens_inf_mathlib}
8226	  \lean{AlgebraicGeometry.isPullback_opens_inf}
8227	  \mathlibok
8228	  \textit{Provided by Mathlib.}
8229	  For two opens \(U, V\) of a scheme \(X\), the square with vertex \((U \sqcap V).\mathrm{toScheme}\)
8230	  and the two \(\operatorname{homOfLE}\) inclusions into \(U\) and \(V\) is a pullback of the open
8231	  immersions \(U.\iota, V.\iota\). Equivalently \(\operatorname{pullback} U.\iota\,V.\iota \cong
8232	  (U \sqcap V).\mathrm{toScheme}\): the fibre product of open immersions over \(X\) is the
8233	  intersection of their images.
8234	\end{lemma}
8235	
8236	\begin{lemma}[A wide pullback over a terminal base is the product of its legs]
8237	  \label{lem:widePullbackCone_isLimitOfFan_mathlib}
8238	  \lean{CategoryTheory.Limits.WidePullbackCone.isLimitOfFan}
8239	  \mathlibok
8240	  \textit{Provided by Mathlib.}
8241	  When the base of a wide pullback is a terminal object, a limiting fan of the legs is a limit of
8242	  the wide-pullback diagram. Hence in \(\operatorname{Over} S\) --- where \(\operatorname{Over.mk}
8243	  (\mathrm{id}_S)\) is terminal --- the wide pullback over \(S\) of a family is the product of the
8244	  legs in the slice, which is what lets the fibre power over \(S\) be treated as an iterated
8245	  product in Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8246	\end{lemma}
8247	
8248	\begin{lemma}[The identity arrow is terminal in the slice category]
8249	  \label{lem:over_mkIdTerminal_mathlib}
8250	  \lean{CategoryTheory.Over.mkIdTerminal}
8251	  \mathlibok
8252	  \textit{Provided by Mathlib.}
8253	  For an object \(S\) of a category, \(\operatorname{Over.mk}(\mathrm{id}_S)\) is a terminal object
8254	  of the slice category \(\operatorname{Over} S\). This is what makes the base of a wide pullback
8255	  over \(S\) terminal in the slice, so that
8256	  Lemma~\ref{lem:widePullbackCone_isLimitOfFan_mathlib} exhibits the fibre power over \(S\) as the
8257	  product in \(\operatorname{Over} S\) in Lemma~\ref{lem:widePullback_overX_eq_prod}.
8258	\end{lemma}
